#[cfg(feature = "backend-geometry")]
pub fn run_geometry_probe() -> GeometryProbe {
    let points = [
        Point3::new(-12.0_f32, 4.0_f32, 3.0_f32),
        Point3::new(8.0_f32, -6.0_f32, 2.5_f32),
        Point3::new(4.5_f32, 7.5_f32, 9.0_f32),
        Point3::new(-1.0_f32, 2.0_f32, -4.0_f32),
    ];

    let centroid_sum = points
        .iter()
        .fold(Vector3::zeros(), |acc, point| acc + point.coords);
    let centroid = centroid_sum / points.len() as f32;

    let min = ParryVector::new(
        points
            .iter()
            .map(|point| point.x)
            .fold(f32::INFINITY, f32::min),
        points
            .iter()
            .map(|point| point.y)
            .fold(f32::INFINITY, f32::min),
        points
            .iter()
            .map(|point| point.z)
            .fold(f32::INFINITY, f32::min),
    );
    let max = ParryVector::new(
        points
            .iter()
            .map(|point| point.x)
            .fold(f32::NEG_INFINITY, f32::max),
        points
            .iter()
            .map(|point| point.y)
            .fold(f32::NEG_INFINITY, f32::max),
        points
            .iter()
            .map(|point| point.z)
            .fold(f32::NEG_INFINITY, f32::max),
    );

    let aabb = Aabb::new(min.into(), max.into());
    let size = aabb.maxs - aabb.mins;

    let tree = RTree::bulk_load(
        points
            .iter()
            .enumerate()
            .map(|(index, point)| IndexedPoint {
                index,
                point: [point.x, point.y, point.z],
            })
            .collect(),
    );

    let nearest_sample_index = tree
        .nearest_neighbor(&[0.5_f32, 1.0_f32, 0.0_f32])
        .map(|nearest| nearest.index)
        .unwrap_or_default();

    GeometryProbe {
        centroid: [centroid.x, centroid.y, centroid.z],
        bounds_min: [aabb.mins.x, aabb.mins.y, aabb.mins.z],
        bounds_max: [aabb.maxs.x, aabb.maxs.y, aabb.maxs.z],
        bounds_size: [size.x, size.y, size.z],
        nearest_sample_index,
        route: "workspace/backend/geometry/probe",
    }
}

