fn validate_existing_file(path: &str) -> Result<PathBuf, String> {
    let path_buf = PathBuf::from(path);

    if !path_buf.exists() {
        return Err(format!("File does not exist: {path}"));
    }

    if !path_buf.is_file() {
        return Err(format!("Path is not a file: {path}"));
    }

    Ok(path_buf)
}

#[cfg(feature = "backend-dicom")]
fn read_dicom_string(obj: &dicom_object::DefaultDicomObject, name: &str) -> Option<String> {
    obj.element_by_name(name)
        .ok()
        .and_then(|element| element.to_str().ok())
        .map(|value| value.into_owned())
}

#[cfg(feature = "backend-dicom")]
pub fn inspect_dicom_metadata(path: String) -> Result<DicomInspection, String> {
    let path_buf = validate_existing_file(&path)?;
    let object = dicom_object::open_file(&path_buf)
        .map_err(|error| format!("Failed to open DICOM file {}: {error}", path_buf.display()))?;

    Ok(DicomInspection {
        path: path_buf.display().to_string(),
        patient_name: read_dicom_string(&object, "PatientName"),
        modality: read_dicom_string(&object, "Modality"),
        study_date: read_dicom_string(&object, "StudyDate"),
        series_description: read_dicom_string(&object, "SeriesDescription"),
        route: "workspace/backend/dicom/inspect",
    })
}

#[cfg(not(feature = "backend-dicom"))]
pub fn inspect_dicom_metadata(path: String) -> Result<DicomInspection, String> {
    let _ = validate_existing_file(&path)?;
    Err("DICOM backend feature is disabled in this build".to_string())
}
